script:
frappe.ui.form.on('Custom Student', {
	first_name: function(frm) {
		set_full_name(frm);
	},
	middle_name: function(frm) {
		set_full_name(frm);
	},
	last_name: function(frm) {
		set_full_name(frm);
	}
});

function set_full_name(frm) {
	let parts = [frm.doc.first_name, frm.doc.middle_name, frm.doc.last_name].filter(Boolean);
	frm.set_value('student_name', parts.join(' '));
}
